+# Confirmation prompt honoring AUTO_YES and TTY; usage: confirm "Message?" || exit 1
+confirm() {
+  local msg="$1"
+  if [[ "${AUTO_YES}" == "1" ]]; then return 0; fi
+  if [[ ! -t 0 ]]; then return 1; fi
+  read -r -p "${msg} [y/N] " _ans || return 1
+  [[ "${_ans}" == "y" || "${_ans}" == "Y" ]]
+}
